164: /**
165:  * Implementation of CorsPolicy that reads from the proto route and virtual host config.
166:  * TODO(wbpcode): move all cors interfaces and implementation to 'extensions/filters/http/cors'.
167:  */
168: template <class ProtoType> class CorsPolicyImplBase : public CorsPolicy {
169: public:
170:   CorsPolicyImplBase(const ProtoType& config,
171:                      Server::Configuration::CommonFactoryContext& factory_context)
172:       : config_(config), loader_(factory_context.runtime()), allow_methods_(config.allow_methods()),
173:         allow_headers_(config.allow_headers()), expose_headers_(config.expose_headers()),
174:         max_age_(config.max_age()) {
175:     for (const auto& string_match : config.allow_origin_string_match()) {
176:       allow_origins_.push_back(
177:           std::make_unique<Matchers::StringMatcherImpl<envoy::type::matcher::v3::StringMatcher>>(
178:               string_match, factory_context));
179:     }
180:     if (config.has_allow_credentials()) {
181:       allow_credentials_ = PROTOBUF_GET_WRAPPED_REQUIRED(config, allow_credentials);
182:     }
183:     if (config.has_allow_private_network_access()) {
184:       allow_private_network_access_ =
185:           PROTOBUF_GET_WRAPPED_REQUIRED(config, allow_private_network_access);
186:     }
187: 
188:     if (config.has_forward_not_matching_preflights()) {
189:       forward_not_matching_preflights_ =
190:           PROTOBUF_GET_WRAPPED_REQUIRED(config, forward_not_matching_preflights);
191:     }
192:   }
193: 
194:   // Router::CorsPolicy
195:   const std::vector<Matchers::StringMatcherPtr>& allowOrigins() const override {
196:     return allow_origins_;
197:   };
198:   const std::string& allowMethods() const override { return allow_methods_; };
199:   const std::string& allowHeaders() const override { return allow_headers_; };
200:   const std::string& exposeHeaders() const override { return expose_headers_; };
201:   const std::string& maxAge() const override { return max_age_; };
202:   const absl::optional<bool>& allowCredentials() const override { return allow_credentials_; };
203:   const absl::optional<bool>& allowPrivateNetworkAccess() const override {
204:     return allow_private_network_access_;
205:   };
206:   bool enabled() const override {
207:     if (config_.has_filter_enabled()) {
208:       const auto& filter_enabled = config_.filter_enabled();
209:       return loader_.snapshot().featureEnabled(filter_enabled.runtime_key(),
210:                                                filter_enabled.default_value());
211:     }
212:     return true;
213:   };
214:   bool shadowEnabled() const override {
215:     if (config_.has_shadow_enabled()) {
216:       const auto& shadow_enabled = config_.shadow_enabled();
217:       return loader_.snapshot().featureEnabled(shadow_enabled.runtime_key(),
218:                                                shadow_enabled.default_value());
219:     }
220:     return false;
221:   };
222:   const absl::optional<bool>& forwardNotMatchingPreflights() const override {
223:     return forward_not_matching_preflights_;
224:   }
225: 
226: private:
227:   const ProtoType config_;
228:   Runtime::Loader& loader_;
229:   std::vector<Matchers::StringMatcherPtr> allow_origins_;
230:   const std::string allow_methods_;
231:   const std::string allow_headers_;
232:   const std::string expose_headers_;
233:   const std::string max_age_;
234:   absl::optional<bool> allow_credentials_{};
235:   absl::optional<bool> allow_private_network_access_{};
236:   absl::optional<bool> forward_not_matching_preflights_{};
237: };
